"use client";

import { Category } from "@/data/categories";

interface SplitVisualizationProps {
  salary: number;
  categories: Category[];
}

function formatCurrency(amount: number): string {
  return new Intl.NumberFormat("de-DE", {
    style: "currency",
    currency: "EUR",
    minimumFractionDigits: 2,
  }).format(amount);
}

export function SplitVisualization({
  salary,
  categories,
}: SplitVisualizationProps) {
  const validCategories = categories.filter((c) => c.name && c.percentage > 0);
  const totalPercentage = validCategories.reduce(
    (sum, c) => sum + c.percentage,
    0,
  );

  if (salary <= 0 || validCategories.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-16 text-muted">
        <svg
          width="48"
          height="48"
          viewBox="0 0 48 48"
          fill="none"
          className="mb-4 opacity-30"
        >
          <circle
            cx="24"
            cy="24"
            r="20"
            stroke="currentColor"
            strokeWidth="2"
          />
          <path
            d="M24 14v10l7 7"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
          />
        </svg>
        <p className="text-sm">
          Enter your salary and set up categories to see the split
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Bar visualization */}
      <div>
        <div className="flex rounded-xl overflow-hidden h-12">
          {validCategories.map((cat) => (
            <div
              key={cat.id}
              className="relative transition-all duration-500 ease-out group"
              style={{
                width: `${(cat.percentage / Math.max(totalPercentage, 100)) * 100}%`,
                backgroundColor: cat.color,
                minWidth: cat.percentage > 0 ? "2px" : "0",
              }}
            >
              <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                <span className="text-[10px] font-medium text-white drop-shadow-sm truncate px-1">
                  {cat.name}
                </span>
              </div>
            </div>
          ))}
          {totalPercentage < 100 && (
            <div
              className="bg-border/30"
              style={{
                width: `${((100 - totalPercentage) / 100) * 100}%`,
              }}
            />
          )}
        </div>
      </div>

      {/* Legend */}
      <div className="flex flex-wrap gap-x-4 gap-y-1">
        {validCategories.map((cat) => (
          <div key={cat.id} className="flex items-center gap-1.5">
            <div
              className="w-2.5 h-2.5 rounded-full shrink-0"
              style={{ backgroundColor: cat.color }}
            />
            <span className="text-xs text-muted">{cat.name}</span>
          </div>
        ))}
      </div>

      {/* Total */}
      <div className="flex items-center justify-between pt-3 border-t border-border">
        <span className="text-sm font-medium text-muted">Total allocated</span>
        <div className="text-right">
          <span className="text-lg font-semibold font-data">
            {formatCurrency((salary * Math.min(totalPercentage, 100)) / 100)}
          </span>
          {totalPercentage < 100 && (
            <p className="text-xs text-muted mt-0.5">
              {formatCurrency(salary - (salary * totalPercentage) / 100)}{" "}
              unallocated
            </p>
          )}
        </div>
      </div>
    </div>
  );
}
