"use client";

import { useForm, useFieldArray } from "react-hook-form";
import { Category, CATEGORY_COLORS } from "@/data/categories";
import { useState, useEffect, useCallback, useRef } from "react";

function AmountInput({
  salary,
  percentage,
  disabled,
  onAmountCommit,
}: {
  salary: number;
  percentage: number;
  disabled: boolean;
  onAmountCommit: (amount: number) => void;
}) {
  const computed =
    salary > 0
      ? (Math.round(((percentage * salary) / 100) * 100) / 100).toString()
      : "";
  const [localValue, setLocalValue] = useState(computed);
  const isFocused = useRef(false);

  // Sync from percentage when not focused
  useEffect(() => {
    if (!isFocused.current) {
      setLocalValue(computed);
    }
  }, [computed]);

  return (
    <div className="relative w-24 shrink-0">
      <span className="absolute left-3 top-1/2 -translate-y-1/2 text-xs text-muted">
        €
      </span>
      <input
        type="text"
        inputMode="decimal"
        placeholder="0.00"
        disabled={disabled}
        className="w-full pl-7 pr-2 py-2 bg-card border border-border rounded-lg text-sm font-data text-foreground placeholder:text-muted/40 transition-colors focus:border-accent disabled:opacity-40 disabled:cursor-not-allowed"
        value={localValue}
        onFocus={(e) => {
          isFocused.current = true;
          e.target.select();
        }}
        onChange={(e) => {
          const val = e.target.value;
          if (val === "" || /^\d*\.?\d*$/.test(val)) {
            setLocalValue(val);
          }
        }}
        onBlur={(e) => {
          isFocused.current = false;
          const amount = parseFloat(e.target.value);
          if (!isNaN(amount) && salary > 0) {
            onAmountCommit(amount);
          } else {
            setLocalValue(computed);
          }
        }}
        onKeyDown={(e) => {
          if (e.key === "Enter") {
            (e.target as HTMLInputElement).blur();
          }
        }}
      />
    </div>
  );
}

interface CategoryManagerProps {
  categories: Category[];
  salary: number;
  onCategoriesChange: (categories: Category[]) => void;
}

interface FormValues {
  categories: Category[];
}

export function CategoryManager({
  categories,
  salary,
  onCategoriesChange,
}: CategoryManagerProps) {
  const {
    register,
    control,
    watch,
    formState: { errors },
    setValue,
  } = useForm<FormValues>({
    defaultValues: { categories },
    mode: "onChange",
  });

  const { fields, append, remove } = useFieldArray({
    control,
    name: "categories",
  });

  const watchedCategories = watch("categories");
  const totalPercentageRaw =
    watchedCategories?.reduce(
      (sum, cat) => sum + (Number(cat.percentage) || 0),
      0,
    ) ?? 0;
  const totalPercentage = Math.round(totalPercentageRaw * 100) / 100;

  const syncCategories = useCallback(() => {
    if (watchedCategories) {
      onCategoriesChange(
        watchedCategories.map((cat) => ({
          ...cat,
          percentage: Number(cat.percentage) || 0,
        })),
      );
    }
  }, [watchedCategories, onCategoriesChange]);

  useEffect(() => {
    syncCategories();
  }, [syncCategories]);

  const addCategory = () => {
    const nextColor = CATEGORY_COLORS[fields.length % CATEGORY_COLORS.length];
    append({
      id: crypto.randomUUID(),
      name: "",
      percentage: 0,
      color: nextColor,
    });
  };

  return (
    <div className="w-full">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-sm font-medium text-muted">Categories</h2>
        <span
          className={`text-xs font-data px-2 py-1 rounded-lg ${
            totalPercentage === 100
              ? "bg-success/15 text-success"
              : totalPercentage > 100
                ? "bg-danger/15 text-danger"
                : "bg-warning/15 text-warning"
          }`}
        >
          {totalPercentage}%
        </span>
      </div>

      <div className="space-y-2">
        {fields.map((field, index) => (
          <div key={field.id} className="flex items-center gap-2 group w-full">
            <input
              type="color"
              className="w-7 h-7 rounded-full border-0 cursor-pointer shrink-0 bg-transparent appearance-none [&::-webkit-color-swatch-wrapper]:p-0 [&::-webkit-color-swatch]:rounded-full [&::-webkit-color-swatch]:border-0 [&::-moz-color-swatch]:rounded-full [&::-moz-color-swatch]:border-0"
              {...register(`categories.${index}.color`)}
            />
            <input
              type="text"
              placeholder="Category name"
              className="flex-1 min-w-0 px-3 py-2 bg-card border border-border rounded-lg text-sm text-foreground placeholder:text-muted/40 transition-colors focus:border-accent"
              {...register(`categories.${index}.name`, {
                required: "Name required",
              })}
            />
            <AmountInput
              salary={salary}
              percentage={watchedCategories?.[index]?.percentage ?? 0}
              disabled={salary <= 0}
              onAmountCommit={(amount) => {
                const pct = Math.round((amount / salary) * 10000) / 100;
                setValue(`categories.${index}.percentage`, Math.min(pct, 100));
              }}
            />
            <div className="relative w-24 shrink-0">
              <input
                type="number"
                min="0"
                max="100"
                step="0.01"
                placeholder="0"
                className="w-full px-3 py-2 pr-7 bg-card border border-border rounded-lg text-sm font-data text-foreground placeholder:text-muted/40 transition-colors focus:border-accent"
                {...register(`categories.${index}.percentage`, {
                  required: true,
                  min: 0,
                  max: 100,
                  valueAsNumber: true,
                })}
              />
              <span className="absolute right-3 top-1/2 -translate-y-1/2 text-xs text-muted">
                %
              </span>
            </div>
            <button
              type="button"
              onClick={() => remove(index)}
              className="w-6 shrink-0 p-1.5 text-muted hover:text-danger opacity-0 group-hover:opacity-100 transition-all cursor-pointer"
              aria-label={`Remove ${field.name || "category"}`}
            >
              <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
                <path
                  d="M4 4l8 8M12 4l-8 8"
                  stroke="currentColor"
                  strokeWidth="1.5"
                  strokeLinecap="round"
                />
              </svg>
            </button>

            {errors.categories?.[index]?.name && (
              <span className="sr-only">
                {errors.categories[index].name?.message}
              </span>
            )}
          </div>
        ))}
      </div>

      <button
        type="button"
        onClick={addCategory}
        className="mt-3 w-full py-2.5 border border-dashed border-border rounded-xl text-sm text-muted hover:text-accent hover:border-accent transition-colors cursor-pointer"
      >
        + Add category
      </button>

      {totalPercentage !== 100 && totalPercentage > 0 && (
        <p
          className={`mt-3 text-xs ${
            totalPercentage > 100 ? "text-danger" : "text-warning"
          }`}
        >
          {totalPercentage > 100
            ? `Over by ${Math.round((totalPercentage - 100) * 100) / 100}% — remove some to reach 100%`
            : `${Math.round((100 - totalPercentage) * 100) / 100}% remaining — add more or adjust`}
        </p>
      )}
    </div>
  );
}
